PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbg: <https://lambdasistemi.github.io/graph-browser/vocab/groups#>
SELECT DISTINCT ?node WHERE {
  ?node gb:group ?g .
  VALUES ?g { gbg:core gbg:actors gbg:actions gbg:lifecycle gbg:thresholds gbg:framework gbg:parameters gbg:ecosystem }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbg: <https://lambdasistemi.github.io/graph-browser/vocab/groups#>
SELECT DISTINCT ?node WHERE {
  ?node gb:group ?g .
  VALUES ?g { gbg:smart-contracts gbg:languages gbg:tooling gbg:protocols gbg:standards }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT ?node WHERE {
  { ?node a gbk:param-group } UNION { ?node a gbk:parameter }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbe: <https://lambdasistemi.github.io/graph-browser/vocab/edges#>
SELECT DISTINCT ?node WHERE {
  { ?e a gb:EdgeAssertion ; gb:predicate gbe:votes%20on ; gb:from ?node }
  UNION
  { ?e a gb:EdgeAssertion ; gb:predicate gbe:votes%20on ; gb:to ?node }
  UNION
  { ?e a gb:EdgeAssertion ; gb:predicate gbe:evaluates%20and%20votes%20on ; gb:from ?node }
  UNION
  { ?e a gb:EdgeAssertion ; gb:predicate gbe:evaluates%20and%20votes%20on ; gb:to ?node }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbg: <https://lambdasistemi.github.io/graph-browser/vocab/groups#>
SELECT DISTINCT ?node WHERE {
  { ?node gb:group gbg:thresholds }
  UNION { ?node gb:nodeId "ratification" }
  UNION { ?node gb:nodeId "voting" }
  UNION { ?node gb:nodeId "enactment" }
}

